/*
 * Xproto.h -- minimal stub for Plan 9 Tk builds.
 * The X11 wire-protocol types defined here are not used by Tk on Plan 9.
 */
#ifndef _XPROTO_H_
#define _XPROTO_H_

#include <stdint.h>

typedef uint8_t  CARD8;
typedef uint16_t CARD16;
typedef uint32_t CARD32;
typedef int8_t   INT8;
typedef int16_t  INT16;
typedef int32_t  INT32;
typedef uint8_t  BYTE;

#endif /* _XPROTO_H_ */
